window.onload = function() {
    // Check if a count already exists in localStorage
    if (localStorage.getItem("count") === null) {
        // If not, initialize it to 1
        localStorage.setItem("count", 1);
    } else {
        // If it does, increment the count
        localStorage.setItem("count", Number(localStorage.getItem("count")) + 1);
    }

    // Get the count from localStorage and set it as the page counter
    var count = localStorage.getItem("count");

    // Display the counter. This is where you'll need to implement
    // logic to control the 8-segment display based on the count.
    document.querySelector(".counter").textContent = count;
}
